INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24015, "2019/07/31 12:00:00", "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 1, 4, 110501, 4, 24, 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24016, "2019/07/31 12:00:00", "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 2, 4, 110501, 1, 24, 4.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24017, "2019/07/31 12:00:00", "マジムンだらけで目が回るさ～！\nふらふらさ～！", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 3, 4, 110501, 4, 24, 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24018, "2019/07/31 12:00:00", "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 4, 1, 110501, 2, 24, 5.2);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24019, "2019/07/31 12:00:00", "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 5, 5, 110501, 6, 24, 4.2);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24020, "2019/07/31 12:00:00", "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 6, 2, 110501, 2, 24, 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24021, "2019/07/31 12:00:00", "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 7, 1, 110501, 6, 24, 6.4);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24022, "2019/07/31 12:00:00", "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 8, 2, 110501, 2, 24, 0.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24023, "2019/07/31 12:00:00", "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 9, 6, 110501, 3, 24, 10.08);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24024, "2019/07/31 12:00:00", "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 10, 1, 110501, 2, 24, 5.0);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES (24025, "2019/07/31 12:00:00", "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 0.0, "2030/12/17 14:59:59", "カオリ（サマー）", 0.0, 10021, 11, 2, 110501, 2, 24, 0.0);
